const trigger = $('When Executed by Another Workflow').first().json;
const lead = trigger.body;
const leadsource = trigger.leadsource || 'website form';

const raw = lead.submittedAt || new Date().toISOString();
const submittedAtIST = new Date(raw).toLocaleString('en-IN', {
  timeZone: 'Asia/Kolkata',
  day: '2-digit',
  month: 'short',
  year: 'numeric',
  hour: '2-digit',
  minute: '2-digit',
  hour12: true
});

const sourcePage = (lead.sourcePage && lead.sourcePage !== 'unknown')
  ? lead.sourcePage
  : 'Website Form';

const note =
  'Returning inquiry from ' + lead.name + ' (' + lead.businessName + '). ' +
  'Segment: ' + lead.segment + ', Volume: ' + lead.volume + '. ' +
  'Re-submitted via ' + sourcePage + ' on ' + submittedAtIST + '.';

return [{
  json: {
    recordId:     $input.first().json.id,
    Name:         lead.name,
    businessName: lead.businessName,
    email:        lead.email,
    phone:        lead.phone,
    segment:      lead.segment,
    volume:       lead.volume,
    sourcePage:   sourcePage,
    leadsource:   leadsource,
    submittedAt:  submittedAtIST,
    status:       'Returning Inquiry',
    note:         note
  }
}];

